import * as api from '../api';

// Action Creators are functions that return an action which is a plain object with type and payload
export const getPosts = () => async (dispatch) => {//redux thunk
    try {
        const {data} = await api.fetchPosts(); // fetchPosts return a response which always has a data object -- destructuring expression
        dispatch({type: 'FETCH ALL', payload: data});
    } catch (error) {
        console.log(error.message);
    }  
}
